What does this program print?

```cpp
#include <iostream>

int safeSqrt(int n) {
    if (n < 0) return -1;
    int root = 0;
    while (root * root < n) ++root;
    if (root * root == n) return root;
    return -1;
}

int main() {
    std::cout << safeSqrt(9)  << '\n';
    std::cout << safeSqrt(7)  << '\n';
    std::cout << safeSqrt(-1) << '\n';
    return 0;
}
```

What does this program print? (Assume `std::cerr` output appears on stdout for this question.)

```cpp
#include <iostream>

int safeDivide(int a, int b) {
    if (b == 0) {
        std::cerr << "Error\n";
        return 0;
    }
    return a / b;
}

int main() {
    std::cout << safeDivide(10, 2) << '\n';
    std::cout << safeDivide(10, 0) << '\n';
    return 0;
}
```
